mapper.select:
select s.id, s.title, case when (s.details->>'trackNumber' ~ '^\d+$') then (s.details->>'trackNumber')::int end track_number, s.album_id from song s
s.title ~* #{criteria.titleSearch}
and exists ( select * from transcription t inner join pub p on t.pub_id = p.id inner join pub_idx pi on p.pub_idx_id = pi.id where t.song_id = s.id and pi.name ~* #{criteria.pubNameSearch} )
and exists ( select * from album a where a.id = s.album_id and a.title ~* #{criteria.albumSearch} )
and ( exists ( select * from song_artist sa inner join artist a on sa.artist_id = a.id where sa.song_id = s.id and a.name ~* #{criteria.artistSearch} ) or exists ( select * from album al inner join artist a on al.primary_artist_id = a.id where al.id = s.album_id and a.name ~* #{criteria.artistSearch} ) )
and s.album_id in
#{albumId}
and exists ( select * from transcription t where t.song_id = s.id and t.pub_id in
#{pubId}
)

exists(select * from transcription t where t.pub_id = p.id)
and (name ~* #{criteria.searchName} or coalesce(details->>'issueName', details->>'edition') ~* #{criteria.searchName})
and pi.type = #{criteria.type}::pub_type
p.pub_date >= #{criteria.dateStart}
and p.pub_date <= #{criteria.dateEnd}
order by p.pub_date nulls first, pi.name, p.details->>'volume' nulls first, p.details->>'issue' nulls first, p.details->>'issueName' nulls first, p.details->>'edition' nulls first, p.id
